mapper.select:
SELECT u.id, u.username, u.real_name, u.student_no, u.phone, u.email, u.role_id, u.status, u.create_time, u.update_time FROM sys_user u WHERE u.is_deleted = 0
AND u.username LIKE CONCAT('%', #{username}, '%')
AND u.real_name LIKE CONCAT('%', #{realName}, '%')
AND u.role_id = #{roleId}
ORDER BY u.create_time DESC LIMIT #{offset}, #{limit}
